# Example: Database sharding simulation

import hashlib
from dataclasses import dataclass, field
from typing import Dict, List, Optional, Any


@dataclass
class Shard:
    id: int
    data: Dict[str, Any] = field(default_factory=dict)

    def store(self, key: str, value: Any):
        self.data[key] = value

    def retrieve(self, key: str) -> Optional[Any]:
        return self.data.get(key)

    def delete(self, key: str) -> bool:
        if key in self.data:
            del self.data[key]
            return True
        return False


class ShardedDatabase:
    """Simulate a sharded database with different sharding strategies."""

    def __init__(self, num_shards: int = 4, strategy: str = "hash"):
        self.num_shards = num_shards
        self.strategy = strategy
        self.shards: List[Shard] = [Shard(id=i) for i in range(num_shards)]
        self.directory: Dict[int, int] = {}  # For directory-based sharding

    def _hash_shard(self, key: str) -> int:
        """Hash-based sharding."""
        hash_value = int(hashlib.md5(key.encode()).hexdigest(), 16)
        return hash_value % self.num_shards

    def _range_shard(self, key: str) -> int:
        """Range-based sharding (assumes numeric keys)."""
        try:
            numeric_key = int(key)
            range_size = 1000000 // self.num_shards
            return min(numeric_key // range_size, self.num_shards - 1)
        except ValueError:
            return self._hash_shard(key)

    def _directory_shard(self, key: str) -> int:
        """Directory-based sharding."""
        if key in self.directory:
            return self.directory[key]
        # Assign to least loaded shard
        shard_sizes = [len(s.data) for s in self.shards]
        shard_id = shard_sizes.index(min(shard_sizes))
        self.directory[key] = shard_id
        return shard_id

    def _get_shard_id(self, key: str) -> int:
        """Route key to appropriate shard."""
        if self.strategy == "hash":
            return self._hash_shard(key)
        elif self.strategy == "range":
            return self._range_shard(key)
        elif self.strategy == "directory":
            return self._directory_shard(key)
        else:
            return self._hash_shard(key)

    def store(self, key: str, value: Any):
        """Store a key-value pair."""
        shard_id = self._get_shard_id(key)
        self.shards[shard_id].store(key, value)

    def retrieve(self, key: str) -> Optional[Any]:
        """Retrieve value by key."""
        shard_id = self._get_shard_id(key)
        return self.shards[shard_id].retrieve(key)

    def delete(self, key: str) -> bool:
        """Delete a key-value pair."""
        shard_id = self._get_shard_id(key)
        return self.shards[shard_id].delete(key)

    def get_stats(self) -> dict:
        """Get sharding statistics."""
        shard_sizes = [len(s.data) for s in self.shards]
        return {
            "strategy": self.strategy,
            "num_shards": self.num_shards,
            "total_records": sum(shard_sizes),
            "shard_sizes": shard_sizes,
            "load_balance": max(shard_sizes) - min(shard_sizes) if shard_sizes else 0,
        }

    def range_query(self, start: str, end: str) -> List[dict]:
        """Simulate a range query (simplified for demonstration)."""
        results = []
        for shard in self.shards:
            for key, value in shard.data.items():
                if start <= key <= end:
                    results.append({"key": key, "value": value})
        return sorted(results, key=lambda x: x["key"])


# Example usage
print("Database Sharding Simulation")
print("=" * 60)

for strategy in ["hash", "range", "directory"]:
    print(f"\nStrategy: {strategy}")
    print("-" * 40)

    db = ShardedDatabase(num_shards=4, strategy=strategy)

    # Store user data
    users = [
        ("user:1001", {"name": "Alice", "email": "alice@example.com"}),
        ("user:1002", {"name": "Bob", "email": "bob@example.com"}),
        ("user:2001", {"name": "Charlie", "email": "charlie@example.com"}),
        ("user:2002", {"name": "Diana", "email": "diana@example.com"}),
        ("user:3001", {"name": "Eve", "email": "eve@example.com"}),
        ("user:1500", {"name": "Frank", "email": "frank@example.com"}),
    ]

    for key, value in users:
        db.store(key, value)
        shard_id = db._get_shard_id(key)
        print(f"  {key} -> Shard {shard_id}")

    stats = db.get_stats()
    print(f"  Shard sizes: {stats['shard_sizes']}")
    print(f"  Load balance (max-min): {stats['load_balance']}")

print("\n" + "=" * 60)
print("Range Query Example (hash strategy):")
print("-" * 40)

db = ShardedDatabase(num_shards=4, strategy="hash")
for key, value in users:
    db.store(key, value)

results = db.range_query("user:1001", "user:2001")
for r in results:
    print(f"  {r['key']}: {r['value']}")
